+                    state
+                        .create_task(scope.region_id(), scope.budget(), async { 0_u8 })
+                        .map(|(_, s)| s.task_id())
+                },
+            ),
+            restart: SupervisionStrategy::Stop,
+            shutdown_budget: Budget::INFINITE,
+            depends_on: vec![],
